import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";

export default function Login() {
  const [email, setEmail] = useState("");
  const [senha, setSenha] = useState("");
  const [erro, setErro] = useState("");
  const [loading, setLoading] = useState(false);
  const { fazerLogin } = useAuth();
  const navigate = useNavigate();

  async function handleSubmit(e) {
    e.preventDefault();
    setErro("");
    setLoading(true);
    try {
      await fazerLogin(email, senha);
      navigate("/");
    } catch {
      setErro("Email ou senha incorretos.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={styles.page}>
      <div style={styles.left}>
        <div style={styles.brand}>
          <h1 style={styles.brandTitle}>Biblioteca</h1>
          <p style={styles.brandSub}>Sistema de Gerenciamento Escolar</p>
        </div>
        <p style={styles.tagline}>
          Organize o acervo, gerencie empréstimos e acompanhe tudo em um só lugar.
        </p>
      </div>

      <div style={styles.right}>
        <div style={styles.card}>
          <h2 style={styles.title}>Entrar</h2>
          <p style={styles.sub}>Acesse com suas credenciais</p>

          {erro && <div className="alert alert-error">{erro}</div>}

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="seu@email.com"
                required
              />
            </div>
            <div className="form-group">
              <label>Senha</label>
              <input
                type="password"
                value={senha}
                onChange={(e) => setSenha(e.target.value)}
                placeholder="••••••••"
                required
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary"
              style={{ width: "100%", justifyContent: "center", marginTop: 8 }}
              disabled={loading}
            >
              {loading ? "Entrando..." : "Entrar"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    display: "flex",
    minHeight: "100vh",
    background: "var(--bg)",
  },
  left: {
    flex: 1,
    background: "linear-gradient(135deg, #141829 0%, #1a2040 100%)",
    borderRight: "1px solid var(--border)",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    padding: "60px",
  },
  brand: { marginBottom: 24 },
  brandTitle: {
    fontFamily: "'DM Serif Display', serif",
    fontSize: 48,
    color: "var(--accent)",
    lineHeight: 1,
  },
  brandSub: {
    fontSize: 13,
    color: "var(--muted)",
    textTransform: "uppercase",
    letterSpacing: "2px",
    marginTop: 8,
  },
  tagline: {
    fontSize: 18,
    color: "var(--text)",
    lineHeight: 1.7,
    maxWidth: 360,
    opacity: 0.7,
  },
  right: {
    width: 440,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    padding: 40,
  },
  card: {
    background: "var(--surface)",
    border: "1px solid var(--border)",
    borderRadius: 14,
    padding: 36,
    width: "100%",
  },
  title: { fontSize: 26, marginBottom: 4 },
  sub: { color: "var(--muted)", fontSize: 14, marginBottom: 24 },
};
